parameters.jsCode:
// ============================================================
// NODE: Validate & Parse Mastery Profile Input
// PURPOSE: Parse the Knowledge Analysis Agent output and
// validate it before starting assessment session.
//
// SUPPORTS NEW KAA FORMAT:
//   - student_id (replaces learner_id)
//   - data_sources.github for GitHub availability
//   - recommendations.priority_order for topic ordering
//   - gap_type (FUNDAMENTAL_GAP / PARTIAL_GAP) for difficulty
//   - observed_error_patterns instead of error_patterns
//   - overall_mastery_score (0-100) instead of overall_skill_level
//
// All OUTPUT field names are IDENTICAL to previous version
// so zero downstream nodes require any changes.
// ============================================================

const body = $input.first().json.body;

// ── Accept both student_id (new format) and learner_id (old format) ──
const learnerId = body.student_id || body.learner_id;
if (!learnerId)        throw new Error('Missing student_id (or learner_id)');
if (!body.mastery_profile) throw new Error('Missing mastery_profile');
if (!body.mastery_profile.knowledge_gaps || body.mastery_profile.knowledge_gaps.length === 0) {
  throw new Error('No knowledge gaps found in mastery_profile');
}

const profile    = body.mastery_profile;
const dataSources = body.data_sources || {};

// ── GitHub availability: new format uses data_sources.github ──
// Old format used profile.github_analysis object
const hasGithub = (dataSources.github === 'available') || !!profile.github_analysis;

// ── Derive overall_skill_level for downstream prompt compatibility ──
// New format: overall_mastery_score 0-100
// Old format: overall_skill_level string
const overallScore = profile.overall_mastery_score || 0;
let derivedSkillLevel = 'beginner';
if (overallScore >= 70)      derivedSkillLevel = 'advanced';
else if (overallScore >= 45) derivedSkillLevel = 'intermediate';

// Keep the original field if it exists (old format), otherwise use derived value
profile.overall_skill_level = profile.overall_skill_level || derivedSkillLevel;

// ── Enrich each knowledge gap for downstream compatibility ──
// New format: observed_error_patterns = { sandbox: [...], quizzes: [...], github: [...] }
// Downstream nodes expect: gap.error_patterns = flat array
// Also map gap_type to a priority string so the sort still works as fallback
const rawGaps = profile.knowledge_gaps;
const enrichedGaps = rawGaps.map(gap => {
  // Flatten observed_error_patterns into error_patterns (what downstream nodes read)
  if (!gap.error_patterns) {
    const obs = gap.observed_error_patterns || {};
    const sandboxErrs = Array.isArray(obs.sandbox) ? obs.sandbox : [];
    const quizErrs    = Array.isArray(obs.quizzes) ? obs.quizzes : [];
    const githubErrs  = Array.isArray(obs.github)  ? obs.github  : [];
    gap.error_patterns = [...sandboxErrs, ...quizErrs, ...githubErrs];
  }

  // Map gap_type to priority string for fallback sort compatibility
  // New format has no gap.priority field - derive it from gap_type
  if (!gap.priority) {
    if (gap.gap_type === 'FUNDAMENTAL_GAP') gap.priority = 'high';
    else if (gap.gap_type === 'PARTIAL_GAP') gap.priority = 'medium';
    else gap.priority = 'low';
  }

  return gap;
});

// Update profile with enriched gaps
profile.knowledge_gaps = enrichedGaps;

// ── Sort topics by priority ──
// New format: recommendations.priority_order gives explicit order (most critical first)
// Old format: sort by gap.priority field
const recommendations = body.recommendations || {};
const priorityOrder   = recommendations.priority_order || [];

let sortedGaps;
if (priorityOrder.length > 0) {
  // Use explicit priority_order from recommendations (new format)
  const gapsByTopic = {};
  enrichedGaps.forEach(g => { gapsByTopic[g.topic] = g; });

  // Start with priority_order topics in order
  const ordered = priorityOrder
    .map(t => gapsByTopic[t])
    .filter(Boolean);

  // Append any gaps not mentioned in priority_order
  const remaining = enrichedGaps.filter(g => !priorityOrder.includes(g.topic));
  sortedGaps = [...ordered, ...remaining];
} else {
  // Fallback: sort by gap.priority field (old format compatibility)
  const priorityMap = { critical: 4, high: 3, medium: 2, low: 1 };
  sortedGaps = [...enrichedGaps].sort((a, b) =>
    (priorityMap[b.priority] || 0) - (priorityMap[a.priority] || 0)
  );
}

// ── Select first topic ──
const selectedTopic = sortedGaps[0];

// ── Determine starting difficulty ──
// New format: use gap_type of the first topic
// FUNDAMENTAL_GAP = always start easy (needs foundation building)
// PARTIAL_GAP     = start medium (has some understanding)
// Old format: used overall_skill_level
let startDifficulty = 'easy';

if (selectedTopic.gap_type === 'PARTIAL_GAP') {
  startDifficulty = 'medium';
} else if (selectedTopic.gap_type === 'FUNDAMENTAL_GAP') {
  startDifficulty = 'easy';
} else {
  // Old format fallback
  if (profile.overall_skill_level === 'intermediate') startDifficulty = 'medium';
  if (profile.overall_skill_level === 'advanced')     startDifficulty = 'hard';
}

// Old format GitHub override (keep for backward compatibility)
if (!selectedTopic.gap_type && hasGithub && profile.github_analysis &&
    profile.github_analysis.code_quality_score > 70) {
  startDifficulty = 'medium';
}

// ── Build session data (ALL field names IDENTICAL to old version) ──
const sessionData = {
  learner_id:              learnerId,
  session_id:              `SESSION_${Date.now()}_${learnerId}`,
  mastery_profile:         profile,
  has_github_access:       hasGithub,
  selected_topic:          selectedTopic.topic,
  selected_topic_details:  selectedTopic,
  all_topics:              sortedGaps.map(g => g.topic),
  remaining_topics:        sortedGaps.slice(1).map(g => g.topic),
  current_difficulty:      startDifficulty,
  question_number:         1,
  mastery_score:           0,
  total_questions_asked:   0,
  correct_answers:         0,
  consecutive_correct:     0,
  consecutive_wrong:       0,
  session_history:         [],
  topic_scores:            {},
  mastery_threshold:       85,
  max_questions_per_topic: 10,
  session_started_at:      new Date().toISOString(),
  session_status:          'active'
};

// ── Initialise topic scores (IDENTICAL to old version) ──
sortedGaps.forEach(gap => {
  sessionData.topic_scores[gap.topic] = {
    mastery_score:   0,
    questions_asked: 0,
    correct:         0,
    is_mastered:     false
  };
});

return [{ json: sessionData }];

const raw = $input.first().json;

// ✅ Handle both structures
const session = raw.updated_session || raw;

// ✅ Safe extraction
const topic      = session.selected_topic || "";
const difficulty = session.current_difficulty || "easy";
const profile    = session.mastery_profile || {};

// ✅ Get topic details safely
const topicDetails = (profile.knowledge_gaps || []).find(
  t => t.topic === topic
) || {};

// ─────────────────────────────────────────────
// Bloom's Taxonomy Adaptive Question Scaffold
// ─────────────────────────────────────────────

const bloomsScaffold = {

  // ============================================================
  // EASY LEVEL
  // Bloom's Level 1-2
  // Remembering + Understanding
  // ============================================================

  easy: {

    level_name:
      "Remembering and Understanding (Bloom's Level 1-2)",

    question_type: "mcq",

    instruction: `
Generate a MULTIPLE CHOICE QUESTION (MCQ).

Requirements:
- Exactly 4 options: A, B, C, D
- Only ONE correct answer
- Focus on:
  • definitions
  • syntax recognition
  • concept identification
  • basic understanding
  • terminology

Avoid:
- long coding tasks
- debugging challenges
- complex algorithms

The learner should mainly recall or recognise concepts.
`
  },

  // ============================================================
  // MEDIUM LEVEL
  // Bloom's Level 3-4
  // Applying + Analyzing
  // ============================================================

  medium: {

    level_name:
      "Applying and Analyzing (Bloom's Level 3-4)",

    question_type: "code_completion",

    instruction: `
Generate a Java CODE COMPLETION or CODE TRACING question.

Requirements:
- Include Java code snippet
- Learner must:
  • complete missing logic
  • trace execution flow
  • identify outputs
  • analyze recursion/loops
  • understand program behavior

Focus on:
- applying concepts in code
- analyzing execution
- logical reasoning
- understanding flow

Avoid:
- extremely advanced architecture
- full large-scale implementations

The learner should apply knowledge practically.
`
  },

  // ============================================================
  // HARD LEVEL
  // Bloom's Level 5-6
  // Evaluating + Creating
  // ============================================================

  hard: {

    level_name:
      "Evaluating and Creating (Bloom's Level 5-6)",

    question_type: "coding_challenge",

    instruction: `
Generate a Java DEBUGGING problem or CODING CHALLENGE.

Requirements:
- Include realistic Java code
- Learner must:
  • debug errors
  • optimize logic
  • design solutions
  • implement algorithms
  • evaluate correctness
  • create working code

Focus on:
- problem solving
- debugging ability
- algorithmic thinking
- software design reasoning
- advanced implementation

Avoid:
- simple recall questions
- beginner syntax-only tasks

The learner should demonstrate mastery and independent problem solving.
`
  }
};

const scaffold =
  bloomsScaffold[difficulty] || bloomsScaffold.easy;

// ✅ Safe arrays
const misconceptions =
  topicDetails.misconceptions || [];

// ✅ Extract observed error patterns safely
const errorPatterns =
  Object.values(topicDetails.observed_error_patterns || {})
    .flat()
    .slice(0, 5);

// ✅ Filter previous questions ONLY from current topic
const askedQuestions = (session.session_history || [])
  .filter(h => h.topic === topic)
  .map(h => h.question_text)
  .slice(-5);

// ─────────────────────────────────────────────
// Build stable Ollama prompt
// ─────────────────────────────────────────────

const promptText = `
You are an expert Java tutor.

Generate EXACTLY ONE adaptive Java assessment question.

IMPORTANT RULES:
- Return ONLY valid JSON
- No markdown
- No explanations
- No extra text
- No code fences
- Never return empty output
- Always complete the JSON

TOPIC:
${topic}

DIFFICULTY:
${difficulty}

BLOOM LEVEL:
${scaffold.level_name}

QUESTION REQUIREMENT:
${scaffold.instruction}

KNOWN MISCONCEPTIONS:
${misconceptions.join(', ')}

KNOWN ERROR PATTERNS:
${errorPatterns.join(', ')}

DO NOT REPEAT:
${askedQuestions.join('\n')}

JSON FORMAT:

${difficulty === 'easy'
? `{
  "topic": "${topic}",
  "difficulty": "${difficulty}",
  "blooms_level": "${scaffold.level_name}",
  "question_type": "mcq",
  "question_text": "...",
  "code_snippet": null,
  "options": {
    "A": "...",
    "B": "...",
    "C": "...",
    "D": "..."
  },
  "correct_answer": "A",
  "evaluation_criteria": "...",
  "hints": ["...", "..."]
}`

: `{
  "topic": "${topic}",
  "difficulty": "${difficulty}",
  "blooms_level": "${scaffold.level_name}",
  "question_type": "${scaffold.question_type}",
  "question_text": "...",
  "code_snippet": "Java code here",
  "options": null,
  "correct_answer": null,
  "evaluation_criteria": "...",
  "hints": ["...", "..."]
}`
}
`;

// ─────────────────────────────────────────────
// Ollama Payload
// ─────────────────────────────────────────────

const ollamaPayload = {

  model: "gemma4:latest",

  prompt: promptText,

  stream: false,

  format: "json",

  options: {
    temperature: 0.2,
    num_predict: 1200,
    num_ctx: 4096,
    top_p: 0.9,
    repeat_penalty: 1.1
  }
};

// ─────────────────────────────────────────────
// Final return
// ─────────────────────────────────────────────

return [
  {
    json: {
      ...session,
      question_prompt: promptText,
      bloom_level: scaffold.level_name,
      ollama_payload: ollamaPayload
    }
  }
];

const session = $('Build Question Generation Prompt').first().json;
const ollamaResponse = $input.first().json;

let questionData;

try {

  // ─────────────────────────────────────────────
  // Get raw Ollama response safely
  // ─────────────────────────────────────────────
  let rawText = ollamaResponse.response || '';

  console.log('🟡 RAW OLLAMA RESPONSE:');
  console.log(rawText);

  // ─────────────────────────────────────────────
  // Remove markdown wrappers
  // ─────────────────────────────────────────────
  rawText = rawText
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  // ─────────────────────────────────────────────
  // Extract JSON object safely
  // Handles extra text before/after JSON
  // ─────────────────────────────────────────────
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);

  if (!jsonMatch) {
    throw new Error('No valid JSON object found in Ollama response');
  }

  const cleanedJson = jsonMatch[0];

  console.log('🟢 CLEANED JSON:');
  console.log(cleanedJson);

  // ─────────────────────────────────────────────
  // Parse JSON
  // ─────────────────────────────────────────────
  questionData = JSON.parse(cleanedJson);

  // ─────────────────────────────────────────────
  // Validate required fields
  // ─────────────────────────────────────────────
  const requiredFields = [
    'question_text',
    'question_type',
    'correct_answer',
    'topic',
    'difficulty'
  ];

  for (const field of requiredFields) {

    if (
      questionData[field] === undefined ||
      questionData[field] === null ||
      questionData[field] === ''
    ) {
      throw new Error(`Missing required field: ${field}`);
    }
  }

  // ─────────────────────────────────────────────
  // Ensure question_id always unique
  // ─────────────────────────────────────────────
  questionData.question_id =
    "Q_" +
    Date.now() +
    "_" +
    Math.random().toString(36).substring(2, 8);

  // ─────────────────────────────────────────────
  // Normalize MCQ structure
  // ─────────────────────────────────────────────
  if (questionData.question_type === 'mcq') {

    if (!questionData.options) {
      throw new Error('MCQ missing options object');
    }

    const requiredOptions = ['A', 'B', 'C', 'D'];

    for (const opt of requiredOptions) {

      if (!questionData.options[opt]) {
        throw new Error(`Missing MCQ option: ${opt}`);
      }
    }

    questionData.correct_answer =
      String(questionData.correct_answer)
        .trim()
        .toUpperCase();
  }

  console.log('✅ QUESTION PARSED SUCCESSFULLY');

} catch (e) {

  console.log('❌ QUESTION PARSE FAILED');
  console.log('ERROR:', e.message);

  console.log('🔴 ORIGINAL RESPONSE:');
  console.log(ollamaResponse.response);

  // ❌ IMPORTANT:
  // DO NOT inject unrelated fallback question
  // Throw structured error instead

  throw new Error(
    `Failed to parse adaptive question from Ollama: ${e.message}`
  );
}

// ─────────────────────────────────────────────
// Final return
// ─────────────────────────────────────────────
return [{
  json: {
    ...session,
    current_question: questionData,
    question_generated_at: new Date().toISOString()
  }
}];

