parameters.jsCode:
// ============================================================
// Validate & Extract Session Data
// READS session state from MongoDB (no session_state in request needed)
// Learner only sends: session_id, learner_id, question_id, answer
//
// Priority:
//   1. ame_session_updates (has latest state after first answer)
//   2. ame_sessions (initial state, used for very first answer)
// ============================================================

const body = $('Webhook - Submit Answer').first().json.body;

// ── Validate required fields ──
if (!body.session_id)  throw new Error('Missing session_id');
if (!body.learner_id)  throw new Error('Missing learner_id');
if (!body.question_id) throw new Error('Missing question_id');
if (body.answer === undefined || body.answer === null) throw new Error('Missing answer');

// ── Read from MongoDB - Fetch Session State (ame_session_updates) ──
let sessionUpdateDoc = null;
try {
  const raw = $('MongoDB - Fetch Session State').first().json;
  // n8n returns {} or a doc with _id when found
  if (raw && raw.updated_session) sessionUpdateDoc = raw;
} catch(e) { /* not found */ }

// ── Fallback: read from MongoDB - Fetch Initial Session (ame_sessions) ──
let initialSessionDoc = null;
try {
  const raw = $('MongoDB - Fetch Initial Session').first().json;
  if (raw && raw.session_id) initialSessionDoc = raw;
} catch(e) { /* not found */ }

// ── Read current question from MongoDB - Fetch Current Question ──
let questionDoc = null;
try {
  const raw = $('MongoDB - Fetch Current Question').first().json;
  if (raw && raw.current_question) questionDoc = raw;
} catch(e) { /* not found */ }

// ── Determine session state source ──
// Use ame_session_updates if available (has latest state including mastery updates)
// Fall back to ame_sessions (initial state, used for very first answer submission)
let sessionState;
if (sessionUpdateDoc && sessionUpdateDoc.updated_session) {
  sessionState = sessionUpdateDoc.updated_session;
} else if (initialSessionDoc && initialSessionDoc.session_id) {
  // ame_sessions stores the full initial session fields at root level
  sessionState = initialSessionDoc;
} else {
  throw new Error(
    `No session state found in MongoDB for session_id: ${body.session_id}. ` +
    `Ensure start-session was called first and the session was saved correctly.`
  );
}

// ── Validate question ──
if (!questionDoc || !questionDoc.current_question) {
  throw new Error(
    `No question found in MongoDB for question_id: ${body.question_id}. ` +
    `The question may not have been saved yet.`
  );
}

const currentQuestion = questionDoc.current_question;

// ── Verify question_id matches ──
if (currentQuestion.question_id !== body.question_id) {
  throw new Error(
    `question_id mismatch: request has ${body.question_id} ` +
    `but MongoDB has ${currentQuestion.question_id}`
  );
}

// ── Reconstruct sessionData — IDENTICAL structure as before ──
// Same field names used by ALL downstream nodes — nothing else needs changing
const sessionData = {
  session_id:                sessionState.session_id            || body.session_id,
  learner_id:                sessionState.learner_id            || body.learner_id,
  mastery_profile:           sessionState.mastery_profile,
  selected_topic:            sessionState.selected_topic,
  all_topics:                sessionState.all_topics            || [],
  remaining_topics:          sessionState.remaining_topics      || [],
  current_difficulty:        sessionState.current_difficulty,
  question_number:           sessionState.question_number       || 1,
  mastery_score:             sessionState.mastery_score         || 0,
  total_questions_asked:     sessionState.total_questions_asked || 0,
  correct_answers:           sessionState.correct_answers       || 0,
  consecutive_correct:       sessionState.consecutive_correct   || 0,
  consecutive_wrong:         sessionState.consecutive_wrong     || 0,
  session_history:           sessionState.session_history       || [],
  topic_scores:              sessionState.topic_scores          || {},
  mastery_threshold:         sessionState.mastery_threshold     || 85,
  max_questions_per_topic:   sessionState.max_questions_per_topic || 10,
  session_started_at:        sessionState.session_started_at    || new Date().toISOString(),
  remediation_mode:          sessionState.remediation_mode      || false,
  remediation_questions:     sessionState.remediation_questions || 0,
  max_remediation_questions: sessionState.max_remediation_questions || 6
};

// ── Return identical structure — all downstream nodes unchanged ──
return [{ json: {
  session_id:       body.session_id,
  learner_id:       body.learner_id,
  question_id:      body.question_id,
  submitted_answer: body.answer,
  submitted_at:     new Date().toISOString(),
  sessionData,
  questionData:     { current_question: currentQuestion },
  question:         currentQuestion,
  submittedAnswer:  body.answer
}}];

const data            = $input.first().json;
const question        = data.question;
const submittedAnswer = data.submittedAnswer;

let promptText = null;
let isMcq = false;

if (question.question_type === 'mcq') {
  isMcq = true;
} else {
  promptText = `You are an expert Java programming evaluator. Evaluate this learner's Java answer.

QUESTION:
Topic: ${question.topic}
Difficulty: ${question.difficulty}
Type: ${question.question_type}
Question: ${question.question_text}
${question.code_snippet && question.code_snippet !== 'null' ? `\nCode Provided:\n${question.code_snippet}` : ''}

EXPECTED ANSWER: ${question.correct_answer}
EVALUATION CRITERIA: ${question.evaluation_criteria}
LEARNER ANSWER: ${submittedAnswer}

IMPORTANT: Respond with ONLY a valid JSON object. No explanation, no markdown, no extra text. Just raw JSON.

{
  "is_correct": <true or false>,
  "correctness_score": <number 0-100>,
  "evaluation_summary": "<1-2 sentence summary>",
  "what_is_correct": "<what the learner got right>",
  "what_is_wrong": "<what was wrong, or Nothing if fully correct>",
  "key_concept_understood": <true or false>,
  "partial_credit": <true or false>
}`;
}

const ollamaPayload = promptText ? {
  model: "gemma4:latest",
  format: "json",
  prompt: promptText,
  stream: false,
  options: { temperature: 0.1, num_predict: 1024, num_ctx: 4096, keep_alive: '10m' }
} : null;

return [{ json: {
  ...data,
  evaluationPrompt: promptText,
  is_mcq:           isMcq,
  ollama_payload:   ollamaPayload
}}];

const data      = $input.first().json;
const correct   = String(data.question.correct_answer).trim().toUpperCase();
const submitted = String(data.submittedAnswer).trim().toUpperCase();
const isCorrect = correct === submitted;

return [{ json: {
  ...data,
  evaluation_result: {
    is_correct:             isCorrect,
    correctness_score:      isCorrect ? 100 : 0,
    evaluation_summary:     isCorrect ? 'Correct answer selected.' : `Incorrect. The correct answer was ${correct}.`,
    what_is_correct:        isCorrect ? 'You selected the right option.' : 'N/A',
    what_is_wrong:          isCorrect ? 'Nothing' : `You selected ${submitted} but the correct answer is ${correct}.`,
    key_concept_understood: isCorrect,
    partial_credit:         false
  }
}}];

const evalData       = $('Build Evaluation Prompt').first().json;
const ollamaResponse = $input.first().json;

// Extract question and answer data for smart fallback
const question        = evalData.question        || {};
const submittedAnswer = evalData.submittedAnswer  || '';
const correctAnswer   = question.correct_answer   || '';
const questionText    = question.question_text    || '';
const topic           = question.topic            || 'Java';
const evalCriteria    = question.evaluation_criteria || '';

let evalResult;
let rawResponseText = '';
try {
  const rawText     = ollamaResponse.response || '';
  rawResponseText   = rawText;
  const cleanedText = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  evalResult = JSON.parse(cleanedText);
} catch(e) {
  // ── SMART FALLBACK: use real question/answer data instead of generic text ──
  // Attempt basic string match for MCQ as a safety net
  const submTrim    = String(submittedAnswer).trim().toUpperCase();
  const corrTrim    = String(correctAnswer).trim().toUpperCase();
  const likelyRight = submTrim === corrTrim || corrTrim.startsWith(submTrim) || submTrim.startsWith(corrTrim);

  const whatCorrect = likelyRight
    ? `Your answer "${submittedAnswer}" matches the expected answer for this ${topic} question.`
    : submittedAnswer
      ? `You provided the answer: "${submittedAnswer}" for the question about ${topic}.`
      : `No clear correct elements could be determined from your response.`;

  const whatWrong = likelyRight
    ? 'Nothing - your answer appears correct.'
    : correctAnswer
      ? `Your answer "${submittedAnswer}" did not match the expected answer "${correctAnswer}". ${evalCriteria ? 'Evaluation criteria: ' + evalCriteria : ''}`
      : `Your answer did not match what was expected for this ${topic} question. Please review the concept and try again.`;

  evalResult = {
    is_correct:             likelyRight,
    correctness_score:      likelyRight ? 80 : 0,
    evaluation_summary:     likelyRight
      ? `Your answer appears to match the expected response for this ${topic} question.`
      : `Your answer did not match the expected response for this ${topic} question. The correct answer was: ${correctAnswer || 'see explanation'}.`,
    what_is_correct:        whatCorrect,
    what_is_wrong:          whatWrong,
    key_concept_understood: likelyRight,
    partial_credit:         false,
    _parse_fallback:        true,
    _raw_response_length:   rawResponseText.length
