const data       = $input.first().json;
const evalResult = data.evaluation_result;
const session    = data.sessionData;
const question   = data.question;

// ── Existing mastery calculation (UNCHANGED) ──────────────────
const difficultyWeights = { easy: 0.6, medium: 0.8, hard: 1.0 };
const diffWeight = difficultyWeights[question.difficulty] || 0.6;

const rubricEval  = data.rubric_evaluation || {};
const rubricScore = rubricEval.weighted_rubric_score !== undefined
  ? Number(rubricEval.weighted_rubric_score)
  : (evalResult.is_correct ? 80 : 20);

let rawScore = evalResult.correctness_score || 0;

if (evalResult.is_correct)
  rawScore = Math.max(rawScore, 80);

if (evalResult.partial_credit && !evalResult.is_correct)
  rawScore = Math.max(rawScore, 40);

const blendedScore = Math.round((rawScore * 0.60) + (rubricScore * 0.40));
rawScore = blendedScore;

const weightedScore = rawScore * diffWeight;
const topicKey      = question.topic;

const prevTopicData =
  session.topic_scores?.[topicKey] ||
  { mastery_score: 0, questions_asked: 0, correct: 0 };

const prevMastery = prevTopicData.mastery_score || 0;

let newMastery = Math.round((prevMastery * 0.6) + (weightedScore * 0.4));

if (evalResult.is_correct && newMastery < prevMastery) {
  newMastery = prevMastery;
}

if (evalResult.is_correct) {
  const improvement = question.difficulty === 'hard' ? 8
    : question.difficulty === 'medium' ? 5 : 3;
  newMastery = Math.min(100, Math.max(newMastery, prevMastery + improvement));
} else {
  const penalty = question.difficulty === 'hard' ? 6
    : question.difficulty === 'medium' ? 4 : 2;
  newMastery = Math.max(0, newMastery - penalty);
}

const newConsecutiveCorrect = evalResult.is_correct ? (session.consecutive_correct || 0) + 1 : 0;
const newConsecutiveWrong   = evalResult.is_correct ? 0 : (session.consecutive_wrong  || 0) + 1;

let bonusAdjustedMastery = newMastery;
if (newConsecutiveCorrect >= 3) bonusAdjustedMastery = Math.min(100, newMastery + 5);
if (newConsecutiveWrong   >= 3) bonusAdjustedMastery = Math.max(0,   newMastery - 5);
if (evalResult.is_correct && bonusAdjustedMastery < prevMastery) bonusAdjustedMastery = prevMastery;

// ── CONCEPT-LEVEL REMEDIATION: determine partial-correct ─────
// partial_correct = not binary correct, but score between 30-79
// This means learner has SOME understanding but specific gaps
const isPartialCorrect = (
  !evalResult.is_correct &&
  rawScore >= 30 &&
  rawScore < 80
);

// ── EXTRACT weak concepts from evaluation feedback ────────────
// Sources: what_is_wrong, evaluation_summary, misconceptions
// These become the focus of the NEXT question
const weakConceptSources = [
  evalResult.what_is_wrong         || '',
  evalResult.evaluation_summary    || '',
  rubricEval.concept_misunderstanding || '',
  rubricEval.weaknesses_observed   || '',
  rubricEval.weakest_area          || ''
].filter(s => s && s.length > 5 && s !== 'Nothing');

// Also include known misconceptions from mastery profile for this topic
const topicGap = (session.mastery_profile?.knowledge_gaps || [])
  .find(g => g.topic === topicKey) || {};
const profileMisconceptions = (topicGap.misconceptions || []).slice(0, 2);

const weakConcepts = weakConceptSources.length > 0
  ? weakConceptSources
  : profileMisconceptions;

// ── ADAPTIVE DIFFICULTY — concept-level rules ─────────────────
// KEEP same difficulty for partial-correct (has some understanding)
// DOWNGRADE only when score < 30 (very low — fundamental gap)
// UPGRADE only for fully correct (existing logic)
let nextDifficulty = question.difficulty;

if (evalResult.is_correct && newConsecutiveCorrect >= 2) {
  // Existing: upgrade after 2 consecutive correct
  if (question.difficulty === 'easy')   nextDifficulty = 'medium';
  else if (question.difficulty === 'medium') nextDifficulty = 'hard';

} else if (!evalResult.is_correct) {
  if (isPartialCorrect) {
    // NEW: partial-correct → KEEP same difficulty, focus on weak concept
    nextDifficulty = question.difficulty;
  } else if (rawScore < 30 && newConsecutiveWrong >= 1) {
    // Only downgrade for very low scores (fundamental misunderstanding)
    if (question.difficulty === 'hard')   nextDifficulty = 'medium';
    else if (question.difficulty === 'medium') nextDifficulty = 'easy';
  }
  // score 0-29 but first wrong → keep same (don't downgrade on first failure)
}

// ── Topic transition ──────────────────────────────────────────
const updatedTopicScores = { ...(session.topic_scores || {}) };
updatedTopicScores[topicKey] = {
  mastery_score:   bonusAdjustedMastery,
  questions_asked: (prevTopicData.questions_asked || 0) + 1,
  correct:         (prevTopicData.correct || 0) + (evalResult.is_correct ? 1 : 0),
  is_mastered:     bonusAdjustedMastery >= (session.mastery_threshold || 85)
};

const topicMastered      = bonusAdjustedMastery >= (session.mastery_threshold || 85);
const maxQuestionsReached = updatedTopicScores[topicKey].questions_asked >= (session.max_questions_per_topic || 10);
const moveToNextTopic     = topicMastered || maxQuestionsReached;
const remainingTopics     = session.remaining_topics || [];
const allTopicsMastered   = moveToNextTopic && remainingTopics.length === 0;

let nextTopic           = session.selected_topic;
let nextRemainingTopics = remainingTopics;

if (moveToNextTopic && remainingTopics.length > 0) {
  nextTopic           = remainingTopics[0];
  nextRemainingTopics = remainingTopics.slice(1);
  // Adaptive starting difficulty for new topic
  const nextTopicDetails = (session.mastery_profile?.knowledge_gaps || [])
    .find(t => t.topic === nextTopic) || {};
  if (nextTopicDetails.gap_type === 'PARTIAL_GAP') nextDifficulty = 'medium';
  else if (nextTopicDetails.gap_type === 'FUNDAMENTAL_GAP') nextDifficulty = 'easy';
  else {
    const skill = session.mastery_profile?.overall_skill_level || 'beginner';
    nextDifficulty = skill === 'advanced' ? 'hard' : skill === 'intermediate' ? 'medium' : 'easy';
  }
}

// ── Remediation mode ──────────────────────────────────────────
const questionsOnTopic  = updatedTopicScores[topicKey].questions_asked;
const currentRemMode    = session.remediation_mode || false;
const remQuestions      = session.remediation_questions || 0;
const maxRemQuestions   = session.max_remediation_questions || 6;
let newRemediationMode      = currentRemMode;
let newRemediationQuestions = remQuestions;

if (currentRemMode && bonusAdjustedMastery >= 70) {
  newRemediationMode = false; newRemediationQuestions = 0;
} else if (!currentRemMode && questionsOnTopic >= 5 && bonusAdjustedMastery < 50) {
  newRemediationMode = true;  newRemediationQuestions = 0;
} else if (newRemediationMode) {
  newRemediationQuestions = remQuestions + 1;
}
if (newRemediationMode && newRemediationQuestions >= maxRemQuestions) {
  newRemediationMode = false; newRemediationQuestions = 0;
}

// ── Build history entry — ADD weak_concepts and is_partial_correct ──
const historyEntry = {
  question_id:        question.question_id,
  question_text:      question.question_text,
  question_type:      question.question_type,
  difficulty:         question.difficulty,
  topic:              question.topic,
  submitted_answer:   data.submittedAnswer,
  correct_answer:     question.correct_answer,
  is_correct:         evalResult.is_correct,
  is_partial_correct: isPartialCorrect,
  score:              bonusAdjustedMastery,
  correctness_score:  rawScore,
  // CRITICAL: store extracted weak concepts for next question generation
  weak_concepts:      weakConcepts,
  timestamp:          new Date().toISOString()
};

const updatedHistory = [...(session.session_history || []), historyEntry];

return [{
  json: {
    ...data,

    mastery_calculation: {
      prev_mastery:      prevMastery,
      raw_score:         rawScore,
      weighted_score:    weightedScore,
      new_mastery:       bonusAdjustedMastery,
      difficulty_weight: diffWeight,
      rubric_score:      rubricScore,
      blended_score:     blendedScore,
      is_partial_correct: isPartialCorrect,
      weak_concepts:     weakConcepts
    },

    updated_session: {
      ...session,
      selected_topic:            nextTopic,
      remaining_topics:          nextRemainingTopics,
      current_difficulty:        nextDifficulty,
      question_number:           (session.question_number || 1) + 1,
      total_questions_asked:     (session.total_questions_asked || 0) + 1,
      correct_answers:           (session.correct_answers || 0) + (evalResult.is_correct ? 1 : 0),
      consecutive_correct:       moveToNextTopic && remainingTopics.length > 0 ? 0 : newConsecutiveCorrect,
      consecutive_wrong:         moveToNextTopic && remainingTopics.length > 0 ? 0 : newConsecutiveWrong,
      topic_scores:              updatedTopicScores,
      session_history:           updatedHistory,
      mastery_score:             bonusAdjustedMastery,
      last_updated:              new Date().toISOString(),
      remediation_mode:          newRemediationMode,
      remediation_questions:     newRemediationQuestions,
      max_remediation_questions: maxRemQuestions
    },

    topic_mastered:        topicMastered,
    move_to_next_topic:    moveToNextTopic,
    all_topics_mastered:   allTopicsMastered,
    session_complete:      allTopicsMastered,
    current_topic_mastery: bonusAdjustedMastery,

    remediation_mode:    newRemediationMode,
    remediation_entered: !currentRemMode && newRemediationMode,
    remediation_exited:  currentRemMode  && !newRemediationMode,

    // Pass through for Prepare Next Question
    is_partial_correct: isPartialCorrect,
    weak_concepts:      weakConcepts
  }
}];

