    difficulty: 'medium',
    question_type: 'code_tracing',
    instruction:
      "Generate a Java CODE TRACING problem where learner predicts execution/output."
  },

  L5: {
    name: "Evaluating (Bloom's L5)",
    difficulty: 'hard',
    question_type: 'debugging',
    instruction:
      "Generate a Java DEBUGGING challenge with intentional bugs."
  },

  L6: {
    name: "Creating (Bloom's L6)",
    difficulty: 'hard',
    question_type: 'coding_challenge',
    instruction:
      "Generate a Java CODING CHALLENGE requiring full implementation."
  }
};

function getDifficultyLevel(diff) {

  if (diff === 'easy')   return 'L1';
  if (diff === 'medium') return 'L3';
  if (diff === 'hard')   return 'L5';

  return 'L1';
}

function getNextBloomsLevel(
  currentDiff,
  isCorrect,
  consecCorrect,
  consecWrong,
  isPartial
) {

  const currentLevel =
    getDifficultyLevel(currentDiff);

  const levelOrder =
    ['L1','L2','L3','L4','L5','L6'];

  const currentIdx =
    levelOrder.indexOf(currentLevel);

  if (isCorrect) {

    // Move upward after 2 consecutive correct answers
    if (
      consecCorrect >= 2 &&
      currentIdx < levelOrder.length - 1
    ) {
      return levelOrder[currentIdx + 1];
    }

    return currentLevel;

  } else if (isPartial) {

    // Maintain same level for partial understanding
    return currentLevel;

  } else {

    // Step downward after incorrect answer
    if (
      consecWrong >= 1 &&
      currentIdx > 0
    ) {
      return levelOrder[currentIdx - 1];
    }

    return currentLevel;
  }
}

