  // → analytical remediation (NEVER recall MCQ)
  const needsAnalyticalRemediation = (
    (wasSolvingHard || wasSolvingMedium) && isPartialCorrect
  );

  // Context-aware question type selection
  // needsAnalyticalRemediation → code_tracing or code_completion always
  // Coming from easy + fully wrong → allowed to use structured MCQ briefly
  let remQuestionType, remBloomsLevel, remDifficulty;

  if (needsAnalyticalRemediation) {
    // Learner was doing hard/medium and has partial understanding
    // Preserve cognitive level — use analytical question types
    remDifficulty   = wasSolvingHard ? 'medium' : 'medium';
