const prevData       = $('Prepare Next Question').first().json;
const ollamaResponse = $input.first().json;

let nextQuestion;

try {

  // ─────────────────────────────────────────────
  // Get raw Ollama response safely
  // ─────────────────────────────────────────────
  let rawText = ollamaResponse.response || '';

  console.log('🟡 RAW NEXT QUESTION RESPONSE:');
  console.log(rawText);

  // ─────────────────────────────────────────────
  // Remove markdown wrappers
  // ─────────────────────────────────────────────
  rawText = rawText
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  // ─────────────────────────────────────────────
  // Detect truncated response early
  // ─────────────────────────────────────────────
  if (
    rawText.includes('"hints": [') &&
    !rawText.trim().endsWith('}')
  ) {

    throw new Error(
      'Ollama returned truncated JSON response. Increase token limit or reduce response size.'
    );
  }

  // ─────────────────────────────────────────────
  // Extract JSON safely (PRODUCTION SAFE)
  // ─────────────────────────────────────────────
  const firstBrace = rawText.indexOf('{');
  const lastBrace  = rawText.lastIndexOf('}');

  if (
    firstBrace === -1 ||
    lastBrace === -1
  ) {
    throw new Error(
      'No complete JSON object found in Ollama response'
    );
  }

  const cleanedJson =
    rawText.substring(firstBrace, lastBrace + 1);

  console.log('🟢 CLEANED NEXT QUESTION JSON:');
  console.log(cleanedJson);

  // ─────────────────────────────────────────────
  // Parse JSON safely
  // ─────────────────────────────────────────────
  try {

    nextQuestion = JSON.parse(cleanedJson);

  } catch(parseErr) {

    console.log('❌ JSON PARSE ERROR');
    console.log(parseErr.message);

    // Additional debugging
    console.log('🔴 POSSIBLE TRUNCATED JSON:');
    console.log(
      cleanedJson.substring(
        Math.max(0, cleanedJson.length - 1200)
      )
    );

    throw new Error(
      `Invalid JSON returned by Ollama: ${parseErr.message}`
    );
  }

  // ─────────────────────────────────────────────
  // Normalize alternate Ollama response formats
  // ─────────────────────────────────────────────

  // question → question_text
  if (
    nextQuestion.question &&
    !nextQuestion.question_text
  ) {
    nextQuestion.question_text =
      nextQuestion.question;
  }

  // answer → correct_answer
  if (
    nextQuestion.answer &&
    !nextQuestion.correct_answer
  ) {
    nextQuestion.correct_answer =
      nextQuestion.answer;
  }

  // explanation → evaluation_criteria
  if (
    nextQuestion.explanation &&
    !nextQuestion.evaluation_criteria
  ) {
    nextQuestion.evaluation_criteria =
      nextQuestion.explanation;
  }

  // Auto-detect MCQ
  if (
    nextQuestion.options &&
    !nextQuestion.question_type
  ) {
    nextQuestion.question_type = 'mcq';
  }

  // Auto-fill topic
  if (!nextQuestion.topic) {

    nextQuestion.topic =
      prevData.updated_session.selected_topic;
  }

  // Auto-fill difficulty
  if (!nextQuestion.difficulty) {

    nextQuestion.difficulty =
      prevData.updated_session.current_difficulty;
  }

  // Auto-fill Bloom level
  if (!nextQuestion.blooms_level) {

    nextQuestion.blooms_level =
      prevData.bloom_level || '';
  }

  // ─────────────────────────────────────────────
  // Generate unique question ID
  // ─────────────────────────────────────────────
  nextQuestion.question_id =
    "Q_" +
    Date.now() +
    "_" +
    Math.random().toString(36).substring(2, 8);

  // ─────────────────────────────────────────────
  // Normalize oversized fields
  // Prevent MongoDB / UI overflow
  // ─────────────────────────────────────────────

  if (
    nextQuestion.question_text &&
    nextQuestion.question_text.length > 2500
  ) {

    nextQuestion.question_text =
      nextQuestion.question_text.substring(0, 2500);
  }

  if (
    nextQuestion.code_snippet &&
    nextQuestion.code_snippet.length > 3000
  ) {

    nextQuestion.code_snippet =
      nextQuestion.code_snippet.substring(0, 3000);
  }

  if (
    nextQuestion.evaluation_criteria &&
    nextQuestion.evaluation_criteria.length > 1200
  ) {

    nextQuestion.evaluation_criteria =
      nextQuestion.evaluation_criteria.substring(0, 1200);
  }

  // Limit hints
  if (
    Array.isArray(nextQuestion.hints)
  ) {

    nextQuestion.hints =
      nextQuestion.hints
        .slice(0, 2)
        .map(h =>
          String(h).substring(0, 200)
        );
  }

  // ─────────────────────────────────────────────
  // Validate required fields
  // ─────────────────────────────────────────────
  const requiredFields = [
    'question_text',
    'question_type',
    'topic',
    'difficulty'
  ];

  for (const field of requiredFields) {

    if (
      nextQuestion[field] === undefined ||
      nextQuestion[field] === null ||
      nextQuestion[field] === ''
    ) {

      throw new Error(
        `Missing required field: ${field}`
      );
    }
  }

  // ─────────────────────────────────────────────
  // Validate based on question type
  // ─────────────────────────────────────────────

  const mcqTypes = ['mcq'];

  if (
    mcqTypes.includes(
      nextQuestion.question_type
    )
  ) {

    // ─────────────────────────────────────────────
    // MCQ validation
    // ─────────────────────────────────────────────

    if (!nextQuestion.options) {

      throw new Error(
        'MCQ question missing options'
      );
    }

    // Convert array → object
    if (
      Array.isArray(nextQuestion.options)
    ) {

      if (
        nextQuestion.options.length !== 4
      ) {

        throw new Error(
          'MCQ must contain exactly 4 options'
        );
      }

      nextQuestion.options = {
        A: nextQuestion.options[0],
        B: nextQuestion.options[1],
        C: nextQuestion.options[2],
        D: nextQuestion.options[3]
      };
    }

    // Validate option structure
    const requiredOptions =
      ['A', 'B', 'C', 'D'];

    for (const opt of requiredOptions) {

      if (!nextQuestion.options[opt]) {

        throw new Error(
          `Missing MCQ option: ${opt}`
        );
      }
    }

    // Auto-detect correct answer
    if (
      nextQuestion.correct_answer === undefined ||
      nextQuestion.correct_answer === null ||
      nextQuestion.correct_answer === ''
    ) {

      console.log(
        '⚠️ correct_answer missing. Attempting auto-detection...'
      );

      if (nextQuestion.explanation) {

        const optionEntries =
          Object.entries(nextQuestion.options);

        for (const [key, value] of optionEntries) {

          if (
            String(nextQuestion.explanation)
              .toLowerCase()
              .includes(
                String(value).toLowerCase()
              )
          ) {

            nextQuestion.correct_answer = key;
            break;
          }
        }
      }

      // Safe fallback
      if (!nextQuestion.correct_answer) {

        nextQuestion.correct_answer = 'A';
      }
    }

    // Convert full text → option letter
    const optionEntries =
      Object.entries(nextQuestion.options);

    for (const [key, value] of optionEntries) {

      const optionText =
        String(value).trim().toLowerCase();

      const answerText =
        String(nextQuestion.correct_answer || '')
          .trim()
          .toLowerCase();

      // Exact match
      if (optionText === answerText) {

        nextQuestion.correct_answer = key;
        break;
      }

      // Partial match
      if (
        answerText.includes(optionText)
      ) {

        nextQuestion.correct_answer = key;
        break;
      }
    }

    // Normalize answer
    nextQuestion.correct_answer =
      String(nextQuestion.correct_answer)
        .trim()
        .toUpperCase();

    // Final validation
    const validAnswers =
      ['A', 'B', 'C', 'D'];

    if (
      !validAnswers.includes(
        nextQuestion.correct_answer
      )
    ) {

      throw new Error(
        `Invalid MCQ correct_answer: ${nextQuestion.correct_answer}`
      );
    }

  } else {

    // ─────────────────────────────────────────────
    // Non-MCQ validation
    // ─────────────────────────────────────────────

    nextQuestion.options = null;

    // Remove invalid MCQ-style answers
    if (
      ['A','B','C','D'].includes(
        String(nextQuestion.correct_answer || '')
          .trim()
          .toUpperCase()
      )
    ) {

      console.log(
        '⚠️ Invalid non-MCQ answer format detected. Removing option-letter answer.'
      );

      nextQuestion.correct_answer = null;
    }

    const codeQuestionTypes = [
      'code_completion',
      'code_tracing',
      'debugging',
      'coding_challenge'
    ];

    if (
      codeQuestionTypes.includes(
        nextQuestion.question_type
      ) &&
      !nextQuestion.code_snippet
    ) {

      throw new Error(
        `${nextQuestion.question_type} requires code_snippet`
      );
    }
  }

  console.log(
    '✅ NEXT QUESTION PARSED SUCCESSFULLY'
  );

} catch(e) {

  console.log(
    '❌ NEXT QUESTION PARSE FAILED'
  );

  console.log('ERROR:', e.message);

  console.log('🔴 ORIGINAL RESPONSE:');
  console.log(ollamaResponse.response);

  throw new Error(
    `Failed to parse adaptive next question from Ollama: ${e.message}`
  );
}

