    misconceptions:  gap.misconceptions     || [],
    error_patterns:  gap.error_patterns     || [],
    priority:        gap.priority           || 'medium'
  };
});

// ── Bloom's Taxonomy progression analysis ───────────────────
// Derives cognitive depth reached from question difficulty
const bloomFromDifficulty = { easy: 'L1-L2 (Remembering/Understanding)',
                               medium: 'L3-L4 (Applying/Analyzing)',
                               hard: 'L5-L6 (Evaluating/Creating)' };

const highestDifficultyCorrect = (() => {
  const order = ['hard','medium','easy'];
  for (const d of order) {
    if (history.some(h => h.difficulty === d && h.is_correct)) return d;
  }
  return 'easy';
})();

// Count how many questions at each difficulty level were correct
const diffCounts = { easy:{asked:0,correct:0}, medium:{asked:0,correct:0}, hard:{asked:0,correct:0} };
history.forEach(h => {
  const d = h.difficulty || 'easy';
  if (diffCounts[d]) {
    diffCounts[d].asked++;
    if (h.is_correct) diffCounts[d].correct++;
  }
});

// Question type breakdown
const typeCounts = {};
history.forEach(h => {
  const t = h.question_type || 'unknown';
  if (!typeCounts[t]) typeCounts[t] = { asked:0, correct:0 };
  typeCounts[t].asked++;
  if (h.is_correct) typeCounts[t].correct++;
});

// Consecutive correct streaks (peak)
let peakStreak = 0, curStreak = 0;
history.forEach(h => {
  if (h.is_correct) { curStreak++; peakStreak = Math.max(peakStreak, curStreak); }
  else curStreak = 0;
});

// Mastery progression trajectory (score at each question)
const masteryTrajectory = history.slice(-10).map((h,i) => `Q${history.length-Math.min(10,history.length)+i+1}:${h.score||0}%`).join(' ');

// Difficulty progression string
const diffProgression = history.slice(-10).map((h,i) => `Q${history.length-Math.min(10,history.length)+i+1}:${h.difficulty}`).join(' ');

// Coding questions (non-MCQ) performance
const codingQs = history.filter(h => h.question_type !== 'mcq');
const codingCorrect = codingQs.filter(h => h.is_correct).length;

// MCQ performance
const mcqQs = history.filter(h => h.question_type === 'mcq');
const mcqCorrect = mcqQs.filter(h => h.is_correct).length;

// Observed misconceptions: ONLY include ones explicitly from KAA
// profile for topics where learner was incorrect
const observedMisconceptions = topicDetails.flatMap(t => {
  if (t.correct < t.questions_asked) return t.misconceptions.slice(0,2);
  return [];
});

// Advanced achievement flags
const solvedHardCoding   = history.some(h => h.difficulty === 'hard' && h.question_type !== 'mcq' && h.is_correct);
const reachedL56         = diffCounts.hard.correct > 0;
const highMastery        = summary.overall_mastery >= 85;
const excellentMastery   = summary.overall_mastery >= 90;
const strongAccuracy     = summary.overall_accuracy >= 80;
const allMastered        = topicDetails.every(t => t.is_mastered);

// Per-topic Q&A evidence (compact, factual)
const topicQAEvidence = topicDetails.map(t => {
  const topicHistory = history.filter(h => (h.topic || session.selected_topic) === t.topic);
  const topicCodingCorrect = topicHistory.filter(h => h.question_type !== 'mcq' && h.is_correct).length;
  const topicHardCorrect   = topicHistory.filter(h => h.difficulty === 'hard' && h.is_correct).length;
  const topicHighestCorrect = topicHistory.filter(h => h.is_correct).map(h => h.difficulty).includes('hard') ? 'hard' : topicHistory.filter(h => h.is_correct).map(h => h.difficulty).includes('medium') ? 'medium' : 'easy';
  return `${t.topic}|mastery=${t.mastery_score}%|q=${t.questions_asked}|correct=${t.correct}|acc=${t.accuracy}%|${t.is_mastered?'MASTERED':'NOT_MASTERED'}|highest_correct=${topicHighestCorrect}|coding_correct=${topicCodingCorrect}|hard_correct=${topicHardCorrect}`;
}).join('\n');

// Compact Q&A list with full context for AI to analyze
const truncate = (s, max) =>
  s && s.length > max ? String(s).substring(0, max) + '...' : String(s || '');

const qaDetailedList = fullQaReview.slice(0, 10).map((q, i) =>
  `Q${i+1}|${truncate(q.topic,22)}|${q.difficulty}|${q.question_type}|${q.is_correct?'CORRECT':'WRONG'}|mastery_after=${q.mastery_after||0}%`
).join('\n');

// ── PROMPT ───────────────────────────────────────────────────
// Designed to be within 3500 tokens input + 1200 output = 4700 total
// Keep factual data dense but prompt instructions focused.
const promptText = `You are an expert Java programming instructor writing a FINAL PERSONALIZED FEEDBACK REPORT.

STRICT RULES:
1. Base ALL feedback on the actual session data below. Do NOT invent.
2. FORBIDDEN PHRASES — NEVER use any of these:
   "practice more examples", "review incorrect answers", "attempted all questions",
   "continue learning", "showed persistence", "completed the assessment",
   "retake assessment", "review concepts", "engaged with all topics",
   "needs more practice", "Write 5 Java programs".
3. misconceptions_found MUST be [] (empty array) when a topic has zero errors.
4. key_weaknesses MUST be [] (empty array) when overall_accuracy >= 95%.
5. topic_reports MUST be SPECIFIC to each topic — never copy-paste across topics.
6. improvement_plan MUST name the exact sub-concept the learner struggled with,
   OR if no struggle: recommend the specific NEXT advanced topic to study.
7. If overall_mastery >= 90%: strengths MUST mention algorithmic thinking,
