  const hardTypes        = [...new Set(history.filter(h => h.difficulty === 'hard' && h.is_correct).map(h => h.question_type))];
  const solvedCoding     = history.some(h => ['coding_challenge','debugging','code_completion'].includes(h.question_type) && h.is_correct);
  const reachedL56       = history.some(h => h.difficulty === 'hard' && h.is_correct);

  const diffCounts = { easy:{asked:0,correct:0}, medium:{asked:0,correct:0}, hard:{asked:0,correct:0} };
  history.forEach(h => {
