  const highestCorrect = solvedHard ? 'hard' : history.some(h => h.difficulty === 'medium' && h.is_correct) ? 'medium' : 'easy';
  const bloomLevel     = highestCorrect === 'hard' ? 'Bloom L5-L6 (Evaluating/Creating)' : highestCorrect === 'medium' ? 'Bloom L3-L4 (Applying/Analyzing)' : 'Bloom L1-L2 (Remembering/Understanding)';

  // ── Overall grade ──────────────────────────────────────────
  const grade = overallMastery >= 90 ? 'Excellent'
    : overallMastery >= 75 ? 'Good'
    : overallMastery >= 60 ? 'Satisfactory'
