  if (reachedL56)
    strengths.push(`Progressed to ${bloomLevel} — the highest cognitive level in this session`);
  if (diffCounts.medium.asked > 0 && diffCounts.medium.correct === diffCounts.medium.asked)
    strengths.push(`Solved all ${diffCounts.medium.asked} medium-difficulty code application questions correctly`);
  if (diffCounts.easy.correct === diffCounts.easy.asked && diffCounts.easy.asked > 0)
    strengths.push(`Demonstrated solid foundational recall across ${diffCounts.easy.asked} easy-level questions`);
  if (strengths.length === 0)
    strengths.push(`Completed ${totalQ} questions with ${overallAccuracy}% accuracy at ${bloomLevel}`);

  // ── Key weaknesses — only when errors exist ────────────────
  const weaknesses = [];
  if (overallAccuracy < 80) {
    const incorrectTopics = Object.entries(topicScores)
      .filter(([,s]) => s.correct < s.questions_asked)
