    if (incorrectTopics.length > 0)
      weaknesses.push(`Incorrect answers observed in: ${incorrectTopics.join(', ')} — review the specific sub-concepts involved`);
  }
  // If accuracy >= 95, weaknesses stays []

  // ── Per-topic reports ─────────────────────────────────────
  const topicReports = Object.entries(topicScores).map(([topic, s]) => {
    const gap      = profileGaps.find(g => g.topic === topic) || {};
    const mastery  = s.mastery_score   || 0;
    const asked    = s.questions_asked || 0;
    const correct  = s.correct         || 0;
    const accuracy = asked > 0 ? Math.round((correct/asked)*100) : 0;
    const mastered = s.is_mastered || false;

    const topicHistory  = history.filter(h => (h.topic || session.selected_topic) === topic);
    const hardCorrect   = topicHistory.filter(h => h.difficulty === 'hard' && h.is_correct);
    const codingCorrect = topicHistory.filter(h => h.question_type !== 'mcq' && h.is_correct);
    const hasErrors     = correct < asked;

    // Strength: cite actual question types and difficulty levels solved
    let strength = '';
    if (hardCorrect.length > 0 && codingCorrect.length > 0)
      strength = `Solved ${hardCorrect.length} hard-difficulty ${[...new Set(hardCorrect.map(h=>h.question_type))].join('/')} task(s) correctly on ${topic}, demonstrating deep implementation ability at ${bloomLevel}`;
    else if (codingCorrect.length > 0)
      strength = `Correctly completed ${codingCorrect.length} code-based question(s) on ${topic}, applying concepts in practice`;
    else if (correct === asked && asked > 0)
      strength = `Answered all ${asked} questions correctly on ${topic} with ${accuracy}% accuracy`;
    else
      strength = `Demonstrated partial understanding of ${topic} across ${correct}/${asked} correct answers`;

    // Weakness: only when errors exist, cite specific gap data
    let weakness = 'none observed';
    if (hasErrors) {
