  // ── Motivational message — evidence-based ─────────────────
  let motivation = '';
  if (overallMastery >= 90 && solvedHardCoding)
    motivation = `Outstanding performance — ${overallAccuracy}% accuracy and mastery of ${bloomLevel} demonstrates genuine Java expertise. Your ability to solve hard ${hardTypes.join(' and ')} challenges shows you are ready for professional-level Java development.`;
  else if (overallMastery >= 75)
    motivation = `Strong session performance with ${overallMastery}% mastery. Your progression to ${bloomLevel} confirms solid Java understanding — keep advancing to the next challenge level.`;
  else
    motivation = `Good effort across ${totalQ} questions. Your ${overallMastery}% mastery shows a developing understanding of Java — focus on the specific sub-concepts from this session and your next assessment will show clear improvement.`;

  reportData = {
    report_title:                'Java Programming Assessment - Personalised Feedback Report',
    generated_at:                new Date().toISOString(),
    learner_id:                  session.learner_id,
    session_id:                  session.session_id,
    overall_assessment:          assessment,
    overall_grade:               grade,
    overall_mastery_percentage:  overallMastery,
