    key_strengths:               strengths,
    key_weaknesses:              weaknesses,
    topic_reports:               topicReports,
    mastered_topics:             masteredTopics,
    topics_needing_improvement:  unmasteredTopics,
    misconceptions_to_address:   topicReports.flatMap(t => t.misconceptions_found),
    learning_path: {
      immediate_focus:              immediateFocus,
      next_stage_recommendations:   nextStage,
      advanced_topics_ready_for:    advancedReady,
      week_1_goals:   [ nextStage[0] ],
      long_term_goals: advancedReady.length > 0 ? advancedReady : [ 'Build a complete Java project integrating all assessed topics' ]
    },
    recommended_resources: [
      { topic: 'Java General', resource_name: 'Official Java Documentation', resource_type: 'website', url_hint: 'docs.oracle.com/javase' },
      { topic: 'Java General', resource_name: 'Effective Java — Joshua Bloch', resource_type: 'book', url_hint: 'effectivejava.com' }
