const current_difficulty    = src.current_difficulty    || sess.current_difficulty    || 'easy';
const bloom_level           = src.bloom_level           || (current_question && current_question.blooms_level) || '';

// Spread ALL of src so nothing downstream breaks, then override with guaranteed fields
return [{ json: {
  ...src,
  session_id,
  learner_id,
  current_question,
  question_generated_at,
  current_difficulty,
  bloom_level
}}];

// ============================================================
// Build Rubric Evaluation Prompt
// Question-type-aware rubric — MCQ vs Open-ended
// MCQ: correctness ONLY — no reasoning, no explanation quality
// Open-ended: full multi-dimensional rubric
// ============================================================
const data            = $input.first().json;
const question        = data.question;
const evalResult      = data.evaluation_result;
const submittedAnswer = data.submittedAnswer;
const qType           = question.question_type || 'mcq';
const difficulty      = question.difficulty    || 'easy';
const topic           = question.topic         || 'Java';

// ── Question type classification ────────────────────────────
// MCQ: binary choice — only correctness matters
// Open-ended: multi-dimensional quality evaluation
const isMcq = (qType === 'mcq');

// ── Define rubric criteria by question type ─────────────────
// MCQ: ONLY correctness — single criterion, weight 1.0
// Gemma4 must NOT be asked to evaluate reasoning for MCQ
const rubricsByType = {
  mcq: [
    {
      criterion:   'correctness',
      weight:      1.00,
      description: 'Whether the learner selected the correct answer option. ' +
                   'IMPORTANT: This is a multiple choice question. ' +
                   'Do NOT evaluate reasoning, explanation quality, or conceptual depth. ' +
                   'Score 100 if correct option selected, 0 if wrong option selected.'
    }
  ],
  conceptual: [
    { criterion: 'correctness',              weight: 0.30, description: 'Factual accuracy of the response'                                  },
    { criterion: 'conceptual_understanding', weight: 0.35, description: 'Depth of understanding demonstrated in the explanation'            },
    { criterion: 'logical_reasoning',        weight: 0.25, description: 'Coherence and logical flow of the explanation'                     },
    { criterion: 'authenticity',             weight: 0.10, description: 'Human-like reasoning vs. mechanical/copy-paste response'           }
  ],
  code_completion: [
    { criterion: 'correctness',              weight: 0.35, description: 'Code produces the correct output'                                  },
    { criterion: 'conceptual_understanding', weight: 0.25, description: 'Correct use of Java constructs and concepts'                      },
    { criterion: 'code_quality',             weight: 0.20, description: 'Code readability, naming, and structure'                          },
    { criterion: 'logical_reasoning',        weight: 0.15, description: 'Logical approach used to solve the problem'                       },
    { criterion: 'authenticity',             weight: 0.05, description: 'Genuine learner reasoning vs. template-copied code'               }
  ],
  code_tracing: [
    { criterion: 'correctness',              weight: 0.50, description: 'Correct final output or traced value'                             },
    { criterion: 'logical_reasoning',        weight: 0.35, description: 'Evidence of step-by-step trace reasoning'                        },
    { criterion: 'conceptual_understanding', weight: 0.15, description: 'Shows understanding of what the code does'                       }
  ],
  debugging: [
    { criterion: 'correctness',              weight: 0.30, description: 'All bugs correctly identified and fixed'                         },
    { criterion: 'logical_reasoning',        weight: 0.30, description: 'Systematic debugging approach shown'                             },
    { criterion: 'code_quality',             weight: 0.20, description: 'Fixed code follows good practices'                               },
    { criterion: 'conceptual_understanding', weight: 0.15, description: 'Understands WHY the bugs exist'                                  },
    { criterion: 'authenticity',             weight: 0.05, description: 'Personal debugging process visible'                              }
  ],
  coding_challenge: [
    { criterion: 'correctness',              weight: 0.30, description: 'Solution produces correct output for all cases'                  },
    { criterion: 'logical_reasoning',        weight: 0.25, description: 'Algorithm design and problem-solving approach'                   },
    { criterion: 'code_quality',             weight: 0.20, description: 'Code readability, structure, naming conventions'                 },
    { criterion: 'solution_efficiency',      weight: 0.15, description: 'Time/space complexity and optimal approach'                      },
    { criterion: 'conceptual_understanding', weight: 0.07, description: 'Correct use of Java-specific features'                           },
    { criterion: 'authenticity',             weight: 0.03, description: 'Genuine problem-solving vs. AI-generated pattern'                }
  ],
  descriptive: [
    { criterion: 'correctness',              weight: 0.30, description: 'Factual accuracy of the response'                                },
    { criterion: 'conceptual_understanding', weight: 0.35, description: 'Depth of conceptual understanding demonstrated'                  },
    { criterion: 'logical_reasoning',        weight: 0.25, description: 'Coherence and logical flow of explanation'                       },
    { criterion: 'authenticity',             weight: 0.10, description: 'Human-like reasoning vs. copied response'                        }
  ]
};

// Fallback to coding_challenge for unknown open-ended types
const criteria = rubricsByType[qType] || (isMcq ? rubricsByType['mcq'] : rubricsByType['coding_challenge']);

// Build criteria list for the prompt
const criteriaList = criteria.map(c =>
  `  - ${c.criterion} (weight: ${Math.round(c.weight * 100)}%): ${c.description}`
).join('\n');

const criteriaJson = criteria.map(c =>
  `    {"criterion": "${c.criterion}", "score": <0-100>, "weight": ${c.weight}, "evidence": "<specific evidence from the answer>", "feedback": "<1 sentence specific feedback for this criterion>"}`
).join(',\n');

// ── MCQ-specific prompt (correctness only, no reasoning eval) ──
let promptText;

if (isMcq) {
  const correct   = String(question.correct_answer || '').trim().toUpperCase();
  const submitted = String(submittedAnswer || '').trim().toUpperCase();
  const isCorrect = evalResult.is_correct;
  const score     = isCorrect ? 100 : 0;

  promptText = `You are a Java assessment rubric evaluator.
This is a MULTIPLE CHOICE question. The learner selected a single option letter.

QUESTION CONTEXT:
Topic: ${topic}
Difficulty: ${difficulty.toUpperCase()}
Question Type: MCQ (Multiple Choice)
Question: ${String(question.question_text || '').substring(0, 300)}
Correct Option: ${correct}
Learner Selected: ${submitted}
Result: ${isCorrect ? 'CORRECT' : 'INCORRECT'}

CRITICAL INSTRUCTION:
This is MCQ. You MUST evaluate ONLY whether the correct option was selected.
Do NOT evaluate:
- Reasoning quality
- Explanation depth
- Conceptual articulation
- How well the learner explains their choice
The learner only had to select A, B, C, or D. That is the complete task.

RUBRIC: Single criterion — correctness only.
Correctness score: ${score} (${isCorrect ? '100 because correct option was selected' : '0 because wrong option was selected'})

Respond with ONLY valid JSON:
{
  "rubric_criteria": [
    {"criterion": "correctness", "score": ${score}, "weight": 1.0, "evidence": "${isCorrect ? 'Learner selected the correct option ' + correct : 'Learner selected ' + submitted + ' but correct was ' + correct}", "feedback": "${isCorrect ? 'Correct option selected.' : 'Incorrect option selected. The correct answer was ' + correct + '.'}"}
  ],
  "weighted_rubric_score": ${score},
  "performance_level": "${score === 100 ? 'Excellent' : 'Needs_Improvement'}",
  "strongest_area": "correctness",
  "weakest_area": "${score === 100 ? 'None' : 'correctness'}",
  "reasoning_quality": "N/A - MCQ does not require reasoning",
  "authenticity_flag": "N/A - MCQ",
  "rubric_summary": "${isCorrect ? 'Learner correctly identified option ' + correct + ' for this MCQ question.' : 'Learner selected ' + submitted + ' instead of the correct option ' + correct + '.'}",
  "strengths_observed": "${isCorrect ? 'Correct answer selected.' : 'Attempted the question.'}",
  "weaknesses_observed": "${isCorrect ? 'None' : 'Selected wrong option ' + submitted + '. Correct was ' + correct + '.'}",
  "concept_misunderstanding": ${isCorrect ? 'null' : '"May not fully understand the concept tested by this question."'},
  "improvement_roadmap": "${isCorrect ? 'Continue to the next question.' : 'Review the concept of ' + topic + ' and understand why option ' + correct + ' is correct.'}"
}`;

} else {
  // ── Open-ended prompt (full multi-dimensional rubric) ───────
  promptText = `You are an expert Java programming assessment rubric evaluator.
Evaluate the following learner response using a structured rubric.

QUESTION CONTEXT:
Topic: ${topic}
Difficulty: ${difficulty.toUpperCase()}
Question Type: ${qType}
Question: ${String(question.question_text || '').substring(0, 300)}
${question.code_snippet && question.code_snippet !== 'null' ? `Code Provided:\n${String(question.code_snippet).substring(0, 400)}` : ''}
Expected Answer: ${String(question.correct_answer || '').substring(0, 200)}
Evaluation Criteria: ${question.evaluation_criteria || ''}

LEARNER RESPONSE:
${String(submittedAnswer || '').substring(0, 500)}

INITIAL EVALUATION (for context):
Result: ${evalResult.is_correct ? 'CORRECT' : 'INCORRECT'}
Initial Score: ${evalResult.correctness_score}/100
What was correct: ${String(evalResult.what_is_correct || '').substring(0, 150)}
What was wrong: ${String(evalResult.what_is_wrong || '').substring(0, 150)}

RUBRIC CRITERIA TO EVALUATE:
${criteriaList}

SCORING RULES:
- Score each criterion from 0 to 100
- 0-20: No evidence or completely wrong
- 21-40: Minimal attempt, significant errors
- 41-60: Partial understanding, notable gaps
- 61-80: Good understanding, minor issues
- 81-100: Strong understanding, near perfect

IMPORTANT: Respond with ONLY a valid JSON object. No markdown, no extra text. Just raw JSON:
{
  "rubric_criteria": [
${criteriaJson}
  ],
  "weighted_rubric_score": <calculated weighted average 0-100>,
  "performance_level": "<Excellent|Good|Satisfactory|Needs_Improvement|Poor>",
  "strongest_area": "<criterion name where learner performed best>",
  "weakest_area": "<criterion name where learner needs most improvement>",
  "reasoning_quality": "<Deep|Surface|Minimal|Absent>",
  "authenticity_flag": "<Genuine|Likely_AI_Assisted|Unclear>",
  "rubric_summary": "<2-3 sentence summary of overall rubric performance>",
  "strengths_observed": "<specific strengths seen in the response>",
  "weaknesses_observed": "<specific weaknesses or gaps observed>",
  "concept_misunderstanding": "<any specific misconception identified, or null>",
  "improvement_roadmap": "<concrete step-by-step improvement suggestion>"
}`;
}

const ollamaPayload = {
  model: 'gemma4:latest',
  format: 'json',
  prompt: promptText,
  stream: false,
  // MCQ: smaller context fine, open-ended needs more
  options: isMcq
    ? { temperature: 0.0, num_predict: 600,  num_ctx: 2048, keep_alive: '10m' }
    : { temperature: 0.2, num_predict: 1500, num_ctx: 6144, keep_alive: '10m' }
};

return [{ json: {
  ...data,
  is_mcq_rubric:   isMcq,
  rubric_prompt:   promptText,
  rubric_criteria: criteria,
  ollama_payload:  ollamaPayload
}}];

// ============================================================
// Parse Rubric Result
// Parses Gemma4 rubric response, calculates weighted score.
// MCQ: correctness-only fallback (no reasoning penalties)
// Open-ended: full rubric fallback
// ============================================================
const buildData    = $('Build Rubric Evaluation Prompt').first().json;
const llmResponse  = $input.first().json;
const evalResult   = buildData.evaluation_result;
const question     = buildData.question;
const criteria     = buildData.rubric_criteria || [];
const qType        = question.question_type || 'mcq';
const isMcq        = (qType === 'mcq');

let rubricResult;

try {
  const rawText     = llmResponse.response || '';
  const cleanedText = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  rubricResult      = JSON.parse(cleanedText);

  if (!rubricResult.rubric_criteria || !Array.isArray(rubricResult.rubric_criteria)) {
    throw new Error('Missing rubric_criteria array');
  }

  // Recalculate weighted score from criteria to ensure accuracy
  let calcWeightedScore = 0;
  let totalWeight       = 0;
  for (const c of rubricResult.rubric_criteria) {
    const weight = Number(c.weight) || 0;
    const score  = Math.min(100, Math.max(0, Number(c.score) || 0));
    calcWeightedScore += score * weight;
    totalWeight       += weight;
  }
  if (totalWeight > 0) {
    rubricResult.weighted_rubric_score = Math.round(calcWeightedScore / totalWeight);
  }

  // ── MCQ post-parse enforcement ────────────────────────────
  // Even if Gemma4 returns reasoning fields for MCQ, override them
  if (isMcq) {
    const mcqScore = evalResult.is_correct ? 100 : 0;
    // Force correctness-only score for MCQ
    rubricResult.weighted_rubric_score = mcqScore;
    rubricResult.reasoning_quality     = 'N/A - MCQ does not require reasoning';
    rubricResult.authenticity_flag     = 'N/A - MCQ';
    // Override any reasoning-based criteria scores Gemma4 may have added
    if (rubricResult.rubric_criteria) {
      rubricResult.rubric_criteria = rubricResult.rubric_criteria.map(c => {
        if (c.criterion !== 'correctness') return null; // strip non-correctness criteria
        return { ...c, score: mcqScore, weight: 1.0 };
      }).filter(Boolean);
      // Ensure correctness criterion exists
      if (rubricResult.rubric_criteria.length === 0) {
        rubricResult.rubric_criteria = [{
          criterion: 'correctness',
          score:     mcqScore,
          weight:    1.0,
          evidence:  evalResult.is_correct ? 'Correct option selected' : 'Incorrect option selected',
          feedback:  evalResult.is_correct ? 'Correct.' : `Wrong. Correct was ${question.correct_answer}.`
        }];
      }
    }
  }

} catch(e) {

  if (isMcq) {
    // ── MCQ fallback: correctness ONLY, zero reasoning ──────
    const mcqScore = evalResult.is_correct ? 100 : 0;
    rubricResult = {
      rubric_criteria: [{
        criterion: 'correctness',
        score:     mcqScore,
        weight:    1.0,
        evidence:  evalResult.is_correct
          ? `Learner selected the correct option.`
          : `Learner selected wrong option. Correct was ${question.correct_answer}.`,
        feedback:  evalResult.is_correct
          ? 'Correct answer selected.'
          : `Incorrect. The correct answer is ${question.correct_answer}.`
      }],
      weighted_rubric_score:    mcqScore,
      performance_level:        mcqScore === 100 ? 'Excellent' : 'Needs_Improvement',
      strongest_area:           'correctness',
      weakest_area:             mcqScore === 100 ? 'None' : 'correctness',
      reasoning_quality:        'N/A - MCQ does not require reasoning',
      authenticity_flag:        'N/A - MCQ',
      rubric_summary:           evalResult.is_correct
        ? `Learner correctly answered this MCQ question on ${question.topic}.`
        : `Learner selected the wrong option for this MCQ question on ${question.topic}.`,
      strengths_observed:       evalResult.is_correct ? 'Correct option selected.' : 'Attempted the question.',
      weaknesses_observed:      evalResult.is_correct ? 'None' : `Selected wrong option. Correct was ${question.correct_answer}.`,
      concept_misunderstanding: evalResult.is_correct ? null : `May need to review the concept: ${question.topic}`,
      improvement_roadmap:      evalResult.is_correct
        ? 'Continue to the next question.'
        : `Review ${question.topic} and understand why option ${question.correct_answer} is correct.`,
      _rubric_fallback: true
    };

  } else {
    // ── Open-ended fallback: full rubric from evaluation ────
    const baseScore = evalResult.is_correct ? 80 : 20;
    const fallbackCriteria = criteria.map(c => ({
      criterion: c.criterion,
      score:     evalResult.is_correct
        ? Math.min(100, baseScore + Math.round(c.weight * 20))
        : Math.max(0,   20         - Math.round(c.weight * 10)),
      weight:   c.weight,
      evidence: evalResult.is_correct
        ? `Based on correct answer: ${evalResult.what_is_correct || 'Answer was correct'}`
        : `Based on incorrect answer: ${evalResult.what_is_wrong || 'Answer was wrong'}`,
      feedback: evalResult.is_correct
        ? `Good performance on ${c.criterion}`
        : `Needs improvement in ${c.criterion}`
    }));

    let fallbackWeighted = 0;
    for (const c of fallbackCriteria) { fallbackWeighted += c.score * c.weight; }

    rubricResult = {
      rubric_criteria:          fallbackCriteria,
      weighted_rubric_score:    Math.round(fallbackWeighted),
      performance_level:        evalResult.is_correct ? 'Good' : 'Needs_Improvement',
      strongest_area:           evalResult.is_correct ? (criteria[0]?.criterion || 'correctness') : 'None identified',
      weakest_area:             evalResult.is_correct ? 'None identified' : (criteria[criteria.length-1]?.criterion || 'correctness'),
      reasoning_quality:        evalResult.is_correct ? 'Surface' : 'Minimal',
      authenticity_flag:        'Unclear',
      rubric_summary:           evalResult.is_correct
        ? `The learner answered correctly on this ${question.topic} question.`
        : `The learner answered incorrectly on this ${question.topic} question and needs further practice.`,
      strengths_observed:       evalResult.what_is_correct || 'Attempted the question',
      weaknesses_observed:      evalResult.what_is_wrong   || 'Answer did not match expected',
      concept_misunderstanding: null,
      improvement_roadmap:      `Review the core concepts of ${question.topic} and practice similar ${qType} questions at ${question.difficulty} difficulty.`,
      _rubric_fallback:         true
    };
  }
}

// Clamp weighted_rubric_score to 0-100
rubricResult.weighted_rubric_score = Math.min(100, Math.max(0, rubricResult.weighted_rubric_score || 0));

// Performance level from score if missing
if (!rubricResult.performance_level) {
  const s = rubricResult.weighted_rubric_score;
  rubricResult.performance_level =
    s >= 90 ? 'Excellent' :
    s >= 75 ? 'Good' :
    s >= 60 ? 'Satisfactory' :
    s >= 40 ? 'Needs_Improvement' : 'Poor';
}

return [{ json: { ...buildData, rubric_evaluation: rubricResult }}];
